import sys

class Solution:
    def maxRemovals(self, playlist: str, favoriteSequence: str, removableIndices: list[int]) -> int:
        n = len(playlist)
        m = len(favoriteSequence)
        is_removable = [False] * n
        for idx in removableIndices:
            is_removable[idx] = True

        dp = [[-float('inf')] * (m + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(n):
            cost = 1 if is_removable[i] else 0
            for j in range(m + 1):
                if dp[i][j] == -float('inf'):
                    continue

                dp[i+1][j] = max(dp[i+1][j], dp[i][j] + cost)

                if j < m and playlist[i] == favoriteSequence[j]:
                    dp[i+1][j+1] = max(dp[i+1][j+1], dp[i][j])

        return dp[n][m]

def main():
    import json
    input_data = sys.stdin.read().splitlines()
    if not input_data:
        return

    playlist = json.loads(input_data[0])
    favoriteSequence = json.loads(input_data[1])
    removableIndices = json.loads(input_data[2])

    sol = Solution()
    print(sol.maxRemovals(playlist, favoriteSequence, removableIndices))

