import java.util.*;
import java.io.*;

public class Solution {

    public static long gcd(long a, long b) {
        while (b != 0) {
            long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    public static long lcm(long a, long b) {
        return (a * b) / gcd(a, b);
    }

    public static long calculateGCD(int[] arr) {
        if (arr.length == 0) return 0;
        long result = arr[0];
        for (int i = 1; i < arr.length; i++) {
            result = gcd(result, arr[i]);
        }
        return result;
    }

    public static long calculateLCM(int[] arr) {
        if (arr.length == 0) return 0;
        long result = arr[0];
        for (int i = 1; i < arr.length; i++) {
            result = lcm(result, arr[i]);
        }
        return result;
    }

    public static long calculateMaximumCompositeStrength(int[] strengths) {
        int n = strengths.length;
        if (n == 0) return 0;

        long maxStrength = 0;


        long gcdAll = calculateGCD(strengths);
        long lcmAll = calculateLCM(strengths);
        maxStrength = Math.max(maxStrength, gcdAll * lcmAll);


        for (int i = 0; i < n; i++) {
            int[] remaining = new int[n - 1];
            int idx = 0;
            for (int j = 0; j < n; j++) {
                if (j != i) {
                    remaining[idx++] = strengths[j];
                }
            }

            if (remaining.length == 0) {
                maxStrength = Math.max(maxStrength, 0);
            } else {
                long gcdRemaining = calculateGCD(remaining);
                long lcmRemaining = calculateLCM(remaining);
                maxStrength = Math.max(maxStrength, gcdRemaining * lcmRemaining);
            }
        }

        return maxStrength;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        if (line.startsWith("[") && line.endsWith("]")) {
            line = line.substring(1, line.length() - 1);
        }

        if (line.isEmpty()) {
            System.out.println(0);
            return;
        }

        String[] parts = line.split(",");
        int[] nums = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            nums[i] = Integer.parseInt(parts[i].trim());
        }

        long result = calculateMaximumCompositeStrength(nums);
        System.out.println(result);
    }
}

using namespace std;

class Solution {
public:
    int findMaximumAnomaly(vector<int>& values) {
        long long total_sum = 0;
        unordered_map<int, int> counts;
        for (int x : values) {
            total_sum += x;
            counts[x]++;
        }

        int max_anomaly = -2001;
        int n = values.size();

        for (int i = 0; i < n; ++i) {
            int current_val = values[i];
            long long remaining_sum = total_sum - current_val;
            counts[current_val]--;
            if (counts[current_val] == 0) counts.erase(current_val);

            for (auto const& [val, count] : counts) {
                if ((remaining_sum - val) == (long long)val) {
                    max_anomaly = max(max_anomaly, current_val);
                    break;
                }
            }

            counts[current_val]++;
        }

        return max_anomaly;
    }
};

