class Solution:
    def countValidSelections(self, resources: List[int]) -> int:
        def simulate(start_idx, direction):
            resources_copy = resources[:]
            pos = start_idx
            dir = direction

            while 0 <= pos < len(resources_copy):
                if resources_copy[pos] == 0:
                    pos += dir
                else:
                    resources_copy[pos] -= 1
                    dir = -dir
                    pos += dir

            return all(x == 0 for x in resources_copy)

        count = 0
        for i in range(len(resources)):
            if resources[i] == 0:

                if simulate(i, -1):
                    count += 1

                if simulate(i, 1):
                    count += 1

        return count

