class Solution:
    def maxUniqueItems(self, items: List[int], m: int) -> int:
        items.sort()
        used = set()

        for item in items:
            for val in range(item - m, item + m + 1):
                if val not in used:
                    used.add(val)
                    break

        return len(used)

