import sys

class Solution:
    def countKReducibleElements(self, t: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(t)

        memo_steps = {1: 0}
        def get_steps(x):
            if x in memo_steps:
                return memo_steps[x]
            res = 1 + get_steps(bin(x).count('1'))
            memo_steps[x] = res
            return res

        comb = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n + 1):
            comb[i][0] = 1
            for j in range(1, i + 1):
                comb[i][j] = (comb[i - 1][j - 1] + comb[i - 1][j]) % MOD

        count_less = [0] * (n + 1)
        current_bits = 0
        for i in range(n):
            if t[i] == '1':
                remaining_slots = n - 1 - i
                for b in range(remaining_slots + 1):
                    total_bits = current_bits + b
                    if total_bits > 0:
                        count_less[total_bits] = (count_less[total_bits] + comb[remaining_slots][b]) % MOD
                current_bits += 1

        ans = 0
        for b in range(1, n + 1):
            if get_steps(b) < k:
                ans = (ans + count_less[b]) % MOD

        return ans

def main():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    t = input_data[0]
    k = int(input_data[1])
    sol = Solution()
    print(sol.countKReducibleElements(t, k))

