class Solution:
    def calculateReflectionScore(self, t: str) -> int:
        def get_reflection(c):
            return chr(ord('z') - (ord(c) - ord('a')))

        n = len(t)
        marked = [False] * n
        score = 0

        for i in range(n):
            reflection = get_reflection(t[i])

            for j in range(i - 1, -1, -1):
                if not marked[j] and t[j] == reflection:
                    marked[i] = True
                    marked[j] = True
                    score += i - j
                    break

        return score

def main():
