import sys

class Solution:
    def sumOfAlignedSkylineSubsequences(self, heights: list[int]) -> int:
        MOD = 10**9 + 7
        max_h = 0
        if heights:
            max_h = max(heights)

        count = [0] * (max_h + 2)
        total_sum = [0] * (max_h + 2)
        ans = 0

        for h in heights:
            current_count = 1
            current_sum = h

            for prev_h in [h - 1, h + 1]:
                if 0 <= prev_h <= max_h:
                    current_count = (current_count + count[prev_h]) % MOD
                    current_sum = (current_sum + total_sum[prev_h] + count[prev_h] * h) % MOD

            count[h] = (count[h] + current_count) % MOD
            total_sum[h] = (total_sum[h] + current_sum) % MOD
            ans = (ans + current_sum) % MOD

        return ans

