import math

class Solution:
    def minimumTotalEffort(self, efforts: List[int], k: int, op1: int, op2: int) -> int:
        n = len(efforts)

        dp = {}

        def solve(i, o1, o2):
            if i == n:
                return 0

            if (i, o1, o2) in dp:
                return dp[(i, o1, o2)]

            val = efforts[i]

            options = []

            options.append(val + solve(i + 1, o1, o2))

            if o1 > 0:
                val1 = math.ceil(val / 2)
                options.append(val1 + solve(i + 1, o1 - 1, o2))

            if o2 > 0 and val >= k:
                val2 = val - k
                options.append(val2 + solve(i + 1, o1, o2 - 1))

            if o1 > 0 and o2 > 0:
                if val >= k:
                    val_both1 = math.ceil((val - k) / 2)
                    options.append(val_both1 + solve(i + 1, o1 - 1, o2 - 1))

                val1 = math.ceil(val / 2)
                if val1 >= k:
                    val_both2 = val1 - k
                    options.append(val_both2 + solve(i + 1, o1 - 1, o2 - 1))

            result = min(options)
            dp[(i, o1, o2)] = result
            return result

        return solve(0, op1, op2)

def main():
    efforts = list(map(int, input().split()))
    k = int(input())
    op1 = int(input())
    op2 = int(input())

    solution = Solution()
    result = solution.minimumTotalEffort(efforts, k, op1, op2)
    print(result)

