class Solution:
    def minimumActions(self, items: List[int]) -> int:
        actions = 0
        while len(items) > 0:
            if len(set(items)) == len(items):
                break
            if len(items) >= 3:
                items = items[3:]
            else:
                items = []
            actions += 1
        return actions

