class Solution:
    def countWaysWithXorTreasure(self, maze: list[list[int]], target: int) -> int:
        m = len(maze)
        n = len(maze[0])
        MOD = 10**9 + 7

        dp = [[0] * 16 for _ in range(n)]
        dp[0][maze[0][0]] = 1

        for j in range(1, n):
            val = maze[0][j]
            for x in range(16):
                dp[j][x ^ val] = dp[j-1][x]

        for i in range(1, m):
            new_dp = [[0] * 16 for _ in range(n)]
            val0 = maze[i][0]
            for x in range(16):
                new_dp[0][x ^ val0] = dp[0][x]

            for j in range(1, n):
                val = maze[i][j]
                prev_row = dp[j]
                prev_col = new_dp[j-1]
                curr = new_dp[j]
                for x in range(16):
                    curr[x ^ val] = (prev_row[x] + prev_col[x]) % MOD
            dp = new_dp

        return dp[n-1][target]

def main():
    input_data = sys.stdin.read()
    if not input_data:
        return

    try:
        data = json.loads(input_data)
        if isinstance(data, dict):
            maze = data.get("maze")
            target = data.get("target")
        else:
            maze = data[0]
            target = data[1]

        sol = Solution()
