func main() {
	var N, Y int
	fmt.Scan(&N, &Y)

	servers := make([][4]int, N)
	for i := 0; i < N; i++ {
		fmt.Scan(&servers[i][0], &servers[i][1], &servers[i][2], &servers[i][3])
	}

	canAchieve := func(target int) bool {
		totalCost := 0
		for i := 0; i < N; i++ {
			C, D, E, F := servers[i][0], servers[i][1], servers[i][2], servers[i][3]
			minCost := -1

			maxX := target/C + 1
			for x := 0; x <= maxX; x++ {
				remaining := target - x*C
				if remaining <= 0 {
					cost := x * D
					if minCost == -1 || cost < minCost {
						minCost = cost
					}
				} else {
					y := (remaining + E - 1) / E
					cost := x*D + y*F
					if minCost == -1 || cost < minCost {
						minCost = cost
					}
				}
			}

			if minCost == -1 {
				return false
			}
			totalCost += minCost
			if totalCost > Y {
				return false
			}
		}
		return totalCost <= Y
	}

	left, right := 0, 1000000000
	answer := 0

	for left <= right {
		mid := (left + right) / 2
		if canAchieve(mid) {
			answer = mid
			left = mid + 1
		} else {
			right = mid - 1
		}
	}

	fmt.Println(answer)
}

