		fmt.Fscan(reader, &p[i])
	}

	phi := make([]int, MAXV)
	for i := 0; i < MAXV; i++ {
		phi[i] = i
	}
	for i := 2; i < MAXV; i++ {
		if phi[i] == i {
			for j := i; j < MAXV; j += i {
				phi[j] -= phi[j] / i
			}
		}
	}

	divs := make([][]int, MAXV)
	for i := 1; i < MAXV; i++ {
		for j := i; j < MAXV; j += i {
			divs[j] = append(divs[j], i)
		}
	}

	count := make([]int64, MAXV)
	pow2 := make([]int64, n+1)
	pow2[0] = 1
	for i := 1; i <= n; i++ {
		pow2[i] = (pow2[i-1] * 2) % MOD
	}

	ans := int64(0)
	writer := bufio.NewWriter(os.Stdout)
	for i := 0; i < n; i++ {
		val := p[i]
		currentContribution := int64(0)
		for _, g := range divs[val] {
			currentContribution = (currentContribution + int64(phi[g])*count[g]) % MOD
		}

		ans = (ans*2 + currentContribution) % MOD

		for _, g := range divs[val] {
			count[g] = (count[g] + pow2[i]) % MOD
		}

		fmt.Fprintln(writer, ans)
	}
	writer.Flush()
}

