const int MOD = 1000000007;

long long power(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

long long factorial(int n) {
    long long result = 1;
    for (int i = 1; i <= n; i++) {
        result = (result * i) % MOD;
    }
    return result;
}

long long combination(int n, int k) {
    if (k > n || k < 0) return 0;
    if (k == 0 || k == n) return 1;

    long long num = 1, den = 1;
    for (int i = 0; i < k; i++) {
        num = (num * (n - i)) % MOD;
        den = (den * (i + 1)) % MOD;
    }
    return (num * power(den, MOD - 2, MOD)) % MOD;
}

int main() {
    int n, x, y;
    cin >> n >> x >> y;

    long long result = 0;

    for (int k = 1; k <= min(n, x); k++) {
        long long ways = 0;


        for (int j = 0; j <= k; j++) {
            long long term = combination(k, j) * power(k - j, n, MOD) % MOD;
            if (j % 2 == 0) {
                ways = (ways + term) % MOD;
            } else {
                ways = (ways - term + MOD) % MOD;
            }
        }


        ways = (ways * combination(x, k)) % MOD;


        ways = (ways * power(y, k, MOD)) % MOD;

        result = (result + ways) % MOD;
    }

    cout << result << endl;
    return 0;
}

