func power(a, b int64) int64 {
	res := int64(1)
	mod := int64(1000000007)
	a %= mod
	for b > 0 {
		if b%2 == 1 {
			res = (res * a) % mod
		}
		a = (a * a) % mod
		b /= 2
	}
	return res
}

func solve() {
	var n, x, y int
	if _, err := fmt.Scan(&n, &x, &y); err != nil {
		return
	}

	mod := int64(1000000007)

	fact := make([]int64, x+1)
	invFact := make([]int64, x+1)
	fact[0] = 1
	for i := 1; i <= x; i++ {
		fact[i] = (fact[i-1] * int64(i)) % mod
	}
	invFact[x] = power(fact[x], mod-2)
	for i := x - 1; i >= 0; i-- {
		invFact[i] = (invFact[i+1] * int64(i+1)) % mod
	}

	nCr := func(n, r int) int64 {
		if r < 0 || r > n {
			return 0
		}
		num := fact[n]
		den := (invFact[r] * invFact[n-r]) % mod
		return (num * den) % mod
	}

	totalWays := int64(0)
	yPow := make([]int64, x+1)
	yPow[0] = 1
	yVal := int64(y)
	for i := 1; i <= x; i++ {
		yPow[i] = (yPow[i-1] * yVal) % mod
	}

	dp := make([][]int64, x+1)
	for i := range dp {
		dp[i] = make([]int64, x+1)
	}
	dp[0][0] = 1
	for i := 1; i <= x; i++ {
		for j := 1; j <= i; j++ {
			dp[i][j] = (dp[i-1][j-1] + int64(j)*dp[i-1][j]) % mod
		}
	}

	s2 := make([]int64, n+1)
	if n <= x {
		for k := 0; k <= n; k++ {
			s2[k] = dp[n][k]
		}
	} else {
		curS2 := make([]int64, n+1)
		curS2[0] = 0
		prevS2 := make([]int64, n+1)
		prevS2[0] = 1
		for i := 1; i <= n; i++ {
			for j := 1; j <= i && j <= x; j++ {
				curS2[j] = (prevS2[j-1] + int64(j)*prevS2[j]) % mod
			}
			copy(prevS2, curS2)
		}
		copy(s2, prevS2)
	}

	for k := 0; k <= x && k <= n; k++ {
		term := (nCr(x, k) * s2[k]) % mod
		term = (term * fact[k]) % mod
		term = (term * yPow[k]) % mod
		totalWays = (totalWays + term) % mod
	}

	fmt.Println(totalWays)
}

func main() {
	solve()
}

class Solution {
public:
    bool hasAscendingSegments(std::vector<int>& heights, int m) {
        int n = heights.size();
        std::vector<bool> is_ascending(n - m + 1, false);
        for (int i = 0; i <= n - m; ++i) {
            bool ok = true;
            for (int j = i; j < i + m - 1; ++j) {
                if (heights[j] >= heights[j + 1]) {
                    ok = false;
                    break;
                }
            }
            is_ascending[i] = ok;
        }
        for (int x = 0; x <= n - 2 * m; ++x) {
            if (is_ascending[x] && is_ascending[x + m]) {
                return true;
            }
        }
        return false;
    }
};

