func countValidSelections(resources []int) int {
	n := len(resources)
	validCount := 0

	for start := 0; start < n; start++ {
		if resources[start] == 0 {
			for _, initialDir := range []int{-1, 1} {
				tempResources := make([]int, n)
				copy(tempResources, resources)

				curr := start
				dir := initialDir

				for curr >= 0 && curr < n {
					if tempResources[curr] == 0 {
						curr += dir
					} else {
						tempResources[curr]--
						dir *= -1
						curr += dir
					}
				}

				allZero := true
				for _, val := range tempResources {
					if val != 0 {
						allZero = false
						break
					}
				}
				if allZero {
					validCount++
				}
			}
		}
	}
	return validCount
}

