class Solution:
    def lengthAfterModifications(self, c: str, k: int) -> int:
        MOD = 10**9 + 7

        freq = [0] * 26
        for char in c:
            freq[ord(char) - ord('a')] += 1

        for _ in range(k):
            new_freq = [0] * 26

            for i in range(26):
                if freq[i] == 0:
                    continue

                if i == 12:
                    new_freq[13] = (new_freq[13] + freq[i]) % MOD
                    new_freq[14] = (new_freq[14] + freq[i]) % MOD
                else:
                    next_char = (i + 1) % 26
                    new_freq[next_char] = (new_freq[next_char] + freq[i]) % MOD

            freq = new_freq

        return sum(freq) % MOD

