public class Solution {
    public int computeMinimumTime(int[] difficulty, int M) {
        int n = difficulty.length;
        int[] dp = new int[1 << n];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;

        for (int mask = 0; mask < (1 << n); mask++) {
            if (dp[mask] == Integer.MAX_VALUE) continue;

            int bitsSet = Integer.bitCount(mask);
            int currentY = 1 + bitsSet * M;

            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) == 0) {
                    int newMask = mask | (1 << i);
                    int timeNeeded = (difficulty[i] + currentY - 1) / currentY;
                    dp[newMask] = Math.min(dp[newMask], dp[mask] + timeNeeded);
                }
            }
        }

        return dp[(1 << n) - 1];
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String[] difficultyStr = sc.nextLine().trim().replaceAll("[\\[\\]]", "").split(",");
        int[] difficulty = new int[difficultyStr.length];
        for (int i = 0; i < difficultyStr.length; i++) {
            difficulty[i] = Integer.parseInt(difficultyStr[i].trim());
        }
        int M = sc.nextInt();

        Solution solution = new Solution();
        System.out.println(solution.computeMinimumTime(difficulty, M));
    }
}

