import math

class Solution:
    def computeMinimumTime(self, difficulty: List[int], M: int) -> int:
        n = len(difficulty)
        memo = {}

        def dp(mask, Y):
            if mask == (1 << n) - 1:
                return 0

            if (mask, Y) in memo:
                return memo[(mask, Y)]

            result = float('inf')

            for i in range(n):
                if not (mask & (1 << i)):
                    time_needed = math.ceil(difficulty[i] / Y)
                    new_mask = mask | (1 << i)
                    new_Y = Y + M
                    total_time = time_needed + dp(new_mask, new_Y)
                    result = min(result, total_time)

            memo[(mask, Y)] = result
            return result

        return dp(0, 1)

