const MOD = 1000000007

func power(a, b int64) int64 {
	res := int64(1)
	a %= MOD
	for b > 0 {
		if b%2 == 1 {
			res = (res * a) % MOD
		}
		a = (a * a) % MOD
		b /= 2
	}
	return res
}

func inverse(n int64) int64 {
	return power(n, MOD-2)
}

func nCr(n, r int, fact, invFact []int64) int64 {
	if r < 0 || r > n {
		return 0
	}
	num := fact[n]
	den := (invFact[r] * invFact[n-r]) % MOD
	return (num * den) % MOD
}

func solve() {
	var n, m, k int
	if _, err := fmt.Scan(&n, &m, &k); err != nil {
		return
	}

	if n == 0 {
		fmt.Println(0)
		return
	}

	fact := make([]int64, n+1)
	invFact := make([]int64, n+1)
	fact[0] = 1
	for i := 1; i <= n; i++ {
		fact[i] = (fact[i-1] * int64(i)) % MOD
	}
	invFact[n] = inverse(fact[n])
	for i := n - 1; i >= 0; i-- {
		invFact[i] = (invFact[i+1] * int64(i+1)) % MOD
	}

	comb := nCr(n-1, k, fact, invFact)
	waysToChooseColors := (int64(m) * power(int64(m-1), int64(n-1-k))) % MOD

	result := (comb * waysToChooseColors) % MOD
	fmt.Println(result)
}

