    public int countGoodMosaicSequences(int n, int m, int k) {
        if (n == 0) return 0;
        if (n == 1) return (k == 0) ? m : 0;
        if (m == 1) return (k == n - 1) ? 1 : 0;

        long[] fact = new long[n];
        long[] invFact = new long[n];
        fact[0] = 1;
        invFact[0] = 1;
        for (int i = 1; i < n; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }
        invFact[n - 1] = power(fact[n - 1], MOD - 2);
        for (int i = n - 2; i >= 1; i--) {
            invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
        }

        long combinations = nCr(n - 1, k, fact, invFact);
        long waysToPickColors = (m * power(m - 1, n - 1 - k)) % MOD;

        return (int) ((combinations * waysToPickColors) % MOD);
    }

    private long nCr(int n, int r, long[] fact, long[] invFact) {
        if (r < 0 || r > n) return 0;
        return (((fact[n] * invFact[r]) % MOD) * invFact[n - r]) % MOD;
    }

    private long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }
}

