public class Solution {
    public int elegantDivisions(int[] elements) {
        int n = elements.length;
        int count = 0;

        for (int i = 1; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int[] elements1 = Arrays.copyOfRange(elements, 0, i);
                int[] elements2 = Arrays.copyOfRange(elements, i, j);
                int[] elements3 = Arrays.copyOfRange(elements, j, n);

                if (isPrefix(elements1, elements2) || isPrefix(elements2, elements3)) {
                    count++;
                }
            }
        }

        return count;
    }

    private boolean isPrefix(int[] prefix, int[] array) {
        if (prefix.length > array.length) {
            return false;
        }

        for (int i = 0; i < prefix.length; i++) {
            if (prefix[i] != array[i]) {
                return false;
            }
        }

        return true;
    }

