                    if (match) cond1 = true;
                }

                if (cond1) {
                    count++;
                    continue;
                }

                bool cond2 = false;
                if (len2 <= len3) {
                    bool match = true;
                    for (int k = 0; k < len2; ++k) {
                        if (elements[i + k] != elements[j + k]) {
                            match = false;
                            break;
                        }
                    }
                    if (match) cond2 = true;
                }

                if (cond2) {
                    count++;
                }
            }
        }
        return count;
    }
};

