func main() {
	var n int
	var s, t float64
	if _, err := fmt.Scan(&n, &s, &t); err != nil {
		return
	}

	segments := make([]Segment, n)
	for i := 0; i < n; i++ {
		fmt.Scan(&segments[i].p1.x, &segments[i].p1.y, &segments[i].p2.x, &segments[i].p2.y)
		segments[i].dist = dist(segments[i].p1, segments[i].p2)
	}

	perm := make([]int, n)
	for i := 0; i < n; i++ {
		perm[i] = i
	}

	minTotalTime := math.MaxFloat64

	var generatePermutations func(int)
	generatePermutations = func(k int) {
		if k == n {
			for i := 0; i < (1 << n); i++ {
				currentTime := 0.0
				currentPos := Point{0, 0}
				for j := 0; j < n; j++ {
					idx := perm[j]
					var start, end Point
					if (i>>j)&1 == 0 {
						start = segments[idx].p1
						end = segments[idx].p2
					} else {
						start = segments[idx].p2
						end = segments[idx].p1
					}
					currentTime += dist(currentPos, start) / s
					currentTime += segments[idx].dist / t
					currentPos = end
				}
				if currentTime < minTotalTime {
					minTotalTime = currentTime
				}
			}
			return
		}

		for i := k; i < n; i++ {
			perm[k], perm[i] = perm[i], perm[k]
			generatePermutations(k + 1)
			perm[k], perm[i] = perm[i], perm[k]
		}
	}

	generatePermutations(0)
	fmt.Printf("%.12f\n", minTotalTime)
}

