import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        long Y = sc.nextLong();

        int[] C = new int[N];
        long[] D = new long[N];
        int[] E = new int[N];
        long[] F = new long[N];

        for (int i = 0; i < N; i++) {
            C[i] = sc.nextInt();
            D[i] = sc.nextLong();
            E[i] = sc.nextInt();
            F[i] = sc.nextLong();
        }

        long left = 0, right = 2000000000L;
        long answer = 0;

        while (left <= right) {
            long mid = (left + right) / 2;
            if (canAchieve(N, Y, C, D, E, F, mid)) {
                answer = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        System.out.println(answer);
    }

    static boolean canAchieve(int N, long Y, int[] C, long[] D, int[] E, long[] F, long target) {
        long totalCost = 0;

        for (int i = 0; i < N; i++) {
            long minCost = getMinCost(C[i], D[i], E[i], F[i], target);
            if (minCost == Long.MAX_VALUE) return false;
            totalCost += minCost;
            if (totalCost > Y) return false;
        }

        return totalCost <= Y;
    }

    static long getMinCost(int c, long d, int e, long f, long target) {
        if (target == 0) return 0;

        long minCost = Long.MAX_VALUE;


        long maxR = target / c + 1;
        for (long r = 0; r <= maxR; r++) {
            long remaining = Math.max(0, target - r * c);
            long m = (remaining + e - 1) / e;

            long cost = r * d + m * f;
            minCost = Math.min(minCost, cost);
        }


        long maxM = target / e + 1;
        for (long m = 0; m <= maxM; m++) {
            long remaining = Math.max(0, target - m * e);
            long r = (remaining + c - 1) / c;

            long cost = r * d + m * f;
            minCost = Math.min(minCost, cost);
        }

        return minCost;
    }
}

using namespace std;

struct Server {
    long long c, d, e, f;
};

bool check(long long capacity, int n, long long y, const vector<Server>& servers) {
    long long total_cost = 0;
    for (int i = 0; i < n; ++i) {
        long long min_cost = -1;
        long long c = servers[i].c;
        long long d = servers[i].d;
        long long e = servers[i].e;
        long long f = servers[i].f;

        for (long long r_units = 0; ; ++r_units) {
            long long current_r_cap = r_units * c;
            long long needed_m_cap = max(0LL, capacity - current_r_cap);
            long long m_units = (needed_m_cap + e - 1) / e;
            long long current_cost = r_units * d + m_units * f;

            if (min_cost == -1 || current_cost < min_cost) {
                min_cost = current_cost;
            }

            if (current_r_cap >= capacity) break;

            if (r_units > capacity / c + 1) break;
        }

        long long alt_min_cost = -1;
        for (long long m_units = 0; ; ++m_units) {
            long long current_m_cap = m_units * e;
            long long needed_r_cap = max(0LL, capacity - current_m_cap);
            long long r_units = (needed_r_cap + c - 1) / c;
            long long current_cost = m_units * f + r_units * d;

            if (alt_min_cost == -1 || current_cost < alt_min_cost) {
                alt_min_cost = current_cost;
            }

            if (current_m_cap >= capacity) break;
            if (m_units > capacity / e + 1) break;
        }

        total_cost += min(min_cost, alt_min_cost);
        if (total_cost > y) return false;
    }
    return total_cost <= y;
}

int main() {
    int n;
    long long y;
    if (!(cin >> n >> y)) return 0;
    vector<Server> servers(n);
    for (int i = 0; i < n; ++i) {
        cin >> servers[i].c >> servers[i].d >> servers[i].e >> servers[i].f;
    }

    long long low = 0, high = 2000000000LL;
    long long ans = 0;
    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (mid == 0) {
            ans = max(ans, 0LL);
            low = mid + 1;
            continue;
        }
        if (check(mid, n, y, servers)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    cout << ans << endl;
    return 0;
}

