public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String B = sc.nextLine().strip();

        int n = B.length();
        long count = 0;

        for (int j = 1; j < n - 1; j++) {
            int[] leftCount = new int[26];
            int[] rightCount = new int[26];

            for (int i = 0; i < j; i++) {
                leftCount[B.charAt(i) - 'A']++;
            }

            for (int k = j + 1; k < n; k++) {
                rightCount[B.charAt(k) - 'A']++;
            }

            for (int c = 0; c < 26; c++) {
                count += (long) leftCount[c] * rightCount[c];
            }
        }

        System.out.println(count);
    }
}

