using namespace std;

const int INF = 1e9;

int main() {
    int N;
    if (!(cin >> N)) return 0;

    vector<int> G(N), S(N);
    int total_skill = 0;
    for (int i = 0; i < N; ++i) {
        cin >> G[i] >> S[i];
        total_skill += S[i];
    }

    if (total_skill % 3 != 0) {
        cout << -1 << endl;
        return 0;
    }

    int target = total_skill / 3;
    vector<vector<int>> dp(target + 1, vector<int>(target + 1, INF));
    dp[0][0] = 0;

    for (int i = 0; i < N; ++i) {
        vector<vector<int>> next_dp(target + 1, vector<int>(target + 1, INF));
        for (int s1 = 0; s1 <= target; ++s1) {
            for (int s2 = 0; s2 <= target; ++s2) {
                if (dp[s1][s2] == INF) continue;

                for (int g = 1; g <= 3; ++g) {
                    int ns1 = s1, ns2 = s2;
                    if (g == 1) ns1 += S[i];
                    else if (g == 2) ns2 += S[i];

                    if (ns1 <= target && ns2 <= target) {
                        int cost = (G[i] == g ? 0 : 1);
                        next_dp[ns1][ns2] = min(next_dp[ns1][ns2], dp[s1][s2] + cost);
                    }
                }
            }
        }
        dp = move(next_dp);
    }

    if (dp[target][target] >= INF) {
        cout << -1 << endl;
    } else {
        cout << dp[target][target] << endl;
    }

    return 0;
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] G = new int[N];
        int[] S = new int[N];
        int totalSum = 0;
        for (int i = 0; i < N; i++) {
            G[i] = sc.nextInt();
            S[i] = sc.nextInt();
            totalSum += S[i];
        }

        if (totalSum % 3 != 0) {
            System.out.println("-1");
            return;
        }

        int target = totalSum / 3;
        int[][] dp = new int[target + 1][target + 1];
        for (int i = 0; i <= target; i++) {
            Arrays.fill(dp[i], 1000);
        }
        dp[0][0] = 0;

        for (int i = 0; i < N; i++) {
            int skill = S[i];
            int group = G[i];
            int[][] nextDp = new int[target + 1][target + 1];
            for (int j = 0; j <= target; j++) {
                Arrays.fill(nextDp[j], 1000);
            }

            for (int s1 = 0; s1 <= target; s1++) {
                for (int s2 = 0; s2 <= target; s2++) {
                    if (dp[s1][s2] >= 1000) continue;

                    if (s1 + skill <= target) {
                        int cost = (group == 1) ? 0 : 1;
                        nextDp[s1 + skill][s2] = Math.min(nextDp[s1 + skill][s2], dp[s1][s2] + cost);
                    }

                    if (s2 + skill <= target) {
                        int cost = (group == 2) ? 0 : 1;
                        nextDp[s1][s2 + skill] = Math.min(nextDp[s1][s2 + skill], dp[s1][s2] + cost);
                    }

                    int s3 = totalSum - (s1 + s2);
                    if (s3 >= skill) {
                        int cost = (group == 3) ? 0 : 1;
                        nextDp[s1][s2] = Math.min(nextDp[s1][s2], dp[s1][s2] + cost);
                    }
                }
            }
            dp = nextDp;
        }

        int result = dp[target][target];
        if (result >= 1000) {
            System.out.println("-1");
        } else {
            System.out.println(result);
        }
    }
}

using namespace std;

const long long INF = 1e18;

struct Edge {
    int u, v;
    long long w;
    bool active;
};

struct Query {
    int type;
    int a, b;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N, M, Q;
    cin >> N >> M >> Q;

    vector<Edge> edges(M + 1);
    for (int i = 1; i <= M; ++i) {
        cin >> edges[i].u >> edges[i].v >> edges[i].w;
        edges[i].active = true;
    }

    vector<Query> queries(Q);
    for (int i = 0; i < Q; ++i) {
        cin >> queries[i].type;
        if (queries[i].type == 1) {
            cin >> queries[i].a;
            edges[queries[i].a].active = false;
        } else {
            cin >> queries[i].a >> queries[i].b;
        }
    }

    vector<vector<long long>> dist(N + 1, vector<long long>(N + 1, INF));
    for (int i = 1; i <= N; ++i) dist[i][i] = 0;

    for (int i = 1; i <= M; ++i) {
        if (edges[i].active) {
            int u = edges[i].u;
            int v = edges[i].v;
            long long w = edges[i].w;
            dist[u][v] = min(dist[u][v], w);
            dist[v][u] = min(dist[v][u], w);
        }
    }

    auto run_floyd = [&]() {
        for (int k = 1; k <= N; ++k) {
            for (int i = 1; i <= N; ++i) {
                if (dist[i][k] == INF) continue;
                for (int j = 1; j <= N; ++j) {
                    if (dist[k][j] < INF) {
                        dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);
                    }
                }
            }
        }
    };

    run_floyd();

    vector<long long> results;
    for (int q = Q - 1; q >= 0; --q) {
        if (queries[q].type == 2) {
            long long res = dist[queries[q].a][queries[q].b];
            results.push_back(res >= INF ? -1 : res);
        } else {
            int idx = queries[q].a;
            int u = edges[idx].u;
            int v = edges[idx].v;
            long long w = edges[idx].w;
            if (w < dist[u][v]) {
                dist[u][v] = dist[v][u] = w;
                for (int i = 1; i <= N; ++i) {
                    for (int j = 1; j <= N; ++j) {
                        dist[i][j] = min(dist[i][j], dist[i][u] + w + dist[v][j]);
                        dist[i][j] = min(dist[i][j], dist[i][v] + w + dist[u][j]);
                    }
                }
            }
        }
    }

    reverse(results.begin(), results.end());
    for (long long res : results) {
        cout << res << "\n";
    }

    return 0;
}

import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    ptr = 0
    N = int(input_data[ptr])
    M = int(input_data[ptr+1])
    Q = int(input_data[ptr+2])
    ptr += 3

    edges = []
    for _ in range(M):
        u = int(input_data[ptr]) - 1
        v = int(input_data[ptr+1]) - 1
        w = int(input_data[ptr+2])
        edges.append([u, v, w])
        ptr += 3

    queries = []
    removed_edge_indices = set()
    for _ in range(Q):
        type = int(input_data[ptr])
        if type == 1:
            idx = int(input_data[ptr+1]) - 1
            queries.append((1, idx))
            removed_edge_indices.add(idx)
            ptr += 2
        else:
            u = int(input_data[ptr+1]) - 1
            v = int(input_data[ptr+2]) - 1
            queries.append((2, u, v))
            ptr += 3

    inf = float('inf')
    dist = [[inf] * N for _ in range(N)]
    for i in range(N):
        dist[i][i] = 0

    for i in range(M):
        if i not in removed_edge_indices:
            u, v, w = edges[i]
            if w < dist[u][v]:
                dist[u][v] = dist[v][u] = w

    for k in range(N):
        dk = dist[k]
        for i in range(N):
            di = dist[i]
            if di[k] == inf:
                continue
            for j in range(N):
                if di[j] > di[k] + dk[j]:
                    di[j] = di[k] + dk[j]

    results = []
    rev_queries = queries[::-1]
    for q in rev_queries:
        if q[0] == 1:
            idx = q[1]
            u, v, w = edges[idx]
            if w < dist[u][v]:
                dist[u][v] = dist[v][u] = w
                for i in range(N):
                    di = dist[i]
                    if di[u] == inf:
                        continue
                    for j in range(N):
                        if di[j] > di[u] + w + dist[v][j]:
                            di[j] = di[u] + w + dist[v][j]
                for i in range(N):
                    di = dist[i]
                    if di[v] == inf:
                        continue
                    for j in range(N):
                        if di[j] > di[v] + w + dist[u][j]:
                            di[j] = di[v] + w + dist[u][j]
        else:
            u, v = q[1], q[2]
            res = dist[u][v]
            results.append(res if res != inf else -1)

    sys.stdout.write('\n'.join(map(str, results[::-1])) + '\n')

if __name__ == '__main__':
    solve()

