func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan()
	var n, m int
	fmt.Sscanf(scanner.Text(), "%d %d", &n, &m)

	graph := make([][]int, n+1)

	for i := 0; i < m; i++ {
		scanner.Scan()
		var a, b int
		fmt.Sscanf(scanner.Text(), "%d %d", &a, &b)
		graph[a] = append(graph[a], b)
	}

	result := findShortestCycle(graph, n)
	fmt.Println(result)
}

func findShortestCycle(graph [][]int, n int) int {
	dist := make([]int, n+1)
	for i := range dist {
		dist[i] = -1
	}

	queue := []int{1}
	dist[1] = 0

	for len(queue) > 0 {
		curr := queue[0]
		queue = queue[1:]

		for _, next := range graph[curr] {
			if next == 1 && dist[curr] >= 0 {
				return dist[curr] + 1
			}

			if dist[next] == -1 {
				dist[next] = dist[curr] + 1
				queue = append(queue, next)
			}
		}
	}

	return -1
}

import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());

        int N = Integer.parseInt(st.nextToken());
        int M = Integer.parseInt(st.nextToken());

        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i <= N; i++) {
            graph.add(new ArrayList<>());
        }

        for (int i = 0; i < M; i++) {
            st = new StringTokenizer(br.readLine());
            int a = Integer.parseInt(st.nextToken());
            int b = Integer.parseInt(st.nextToken());
            graph.get(a).add(b);
        }

        int result = findShortestCycle(graph, N);
        System.out.println(result);
    }

    static int findShortestCycle(List<List<Integer>> graph, int N) {
        Queue<Integer> queue = new LinkedList<>();
        int[] dist = new int[N + 1];
        Arrays.fill(dist, -1);

        queue.offer(1);
        dist[1] = 0;

        while (!queue.isEmpty()) {
            int curr = queue.poll();

            for (int next : graph.get(curr)) {
                if (next == 1 && dist[curr] >= 0) {
                    return dist[curr] + 1;
                }

                if (dist[next] == -1) {
                    dist[next] = dist[curr] + 1;
                    queue.offer(next);
                }
            }
        }

        return -1;
    }
}

