        public int compareTo(Tool other) {
            return Integer.compare(this.d, other.d);
        }
    }

    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int T = fr.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fr.nextInt();
            int K = fr.nextInt();
            int[] D = new int[N];
            int[] E = new int[N];
            for (int i = 0; i < N; i++) D[i] = fr.nextInt();
            for (int i = 0; i < N; i++) E[i] = fr.nextInt();

            Tool[] tools = new Tool[N];
            for (int i = 0; i < N; i++) {
                tools[i] = new Tool(D[i], E[i]);
            }
            Arrays.sort(tools);

            PriorityQueue<Integer> pq = new PriorityQueue<>(Collections.reverseOrder());
            long currentSumE = 0;
            long minVal = Long.MAX_VALUE;

            for (int i = 0; i < N; i++) {
                pq.add(tools[i].e);
                currentSumE += tools[i].e;

                if (pq.size() > K) {
                    currentSumE -= pq.poll();
                }

                if (pq.size() == K) {
                    long currentVal = (long) tools[i].d * currentSumE;
                    if (currentVal < minVal) {
                        minVal = currentVal;
                    }
                }
            }
            sb.append(minVal).append("\n");
        }
        System.out.print(sb.toString());
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean fillBuffer() throws IOException {
            bufferLength = in.read(buffer);
            pointer = 0;
            return bufferLength > 0;
        }

        private byte read() throws IOException {
            if (pointer >= bufferLength) {
                if (!fillBuffer()) return -1;
            }
            return buffer[pointer++];
        }

        public int nextInt() throws IOException {
            int c = read();
            while (c >= 0 && c <= 32) c = read();
            if (c == -1) return -1;
            int neg = 1;
            if (c == '-') {
                neg = -1;
                c = read();
            }
            int res = 0;
            while (c > 32) {
                res = res * 10 + (c - '0');
                c = read();
            }
            return res * neg;
        }
    }
}

