                k_temp >>= 1;
            }

            for (int j = 0; j < len; ++j) {
                result[cycle[j]] = cycle[(j + steps) % len];
            }
        }
    }

    for (int i = 1; i <= N; ++i) {
        cout << result[i] << (i == N ? "" : " ");
