struct Node {
    int children[26];
    int min_depth;
    bool exists;

    Node() {
        for (int i = 0; i < 26; ++i) children[i] = -1;
        min_depth = 1e9;
        exists = false;
    }
};

vector<Node> trie;

void insert_and_update(const string& s) {
    int curr = 0;
    vector<int> path;
    path.push_back(curr);
    for (char c : s) {
        int idx = c - 'a';
        if (trie[curr].children[idx] == -1) {
            trie[curr].children[idx] = trie.size();
            trie.push_back(Node());
        }
        curr = trie[curr].children[idx];
        path.push_back(curr);
    }
    trie[curr].exists = true;
    for (int i = 0; i < (int)path.size(); ++i) {
        trie[path[i]].min_depth = min(trie[path[i]].min_depth, (int)s.length() - i);
    }
}

int query(const string& s) {
    int n = s.length();
    int res = n;
    int curr = 0;
    for (int i = 0; i < n; ++i) {
        int idx = s[i] - 'a';
        if (trie[curr].children[idx] == -1) break;
        curr = trie[curr].children[idx];
        res = min(res, (n - (i + 1)) + trie[curr].min_depth);
    }
    return res;
}

