    cin.tie(NULL);

    long long N;
    int M;
    if (!(cin >> N >> M)) return 0;

    vector<pair<long long, long long>> pebbles(M);
    for (int i = 0; i < M; ++i) cin >> pebbles[i].first;
    for (int i = 0; i < M; ++i) cin >> pebbles[i].second;

    sort(pebbles.begin(), pebbles.end());

    long long total_pebbles = 0;
    for (int i = 0; i < M; ++i) total_pebbles += pebbles[i].second;

    if (total_pebbles != N) {
        cout << -1 << endl;
        return 0;
    }

    long long current_pos = 1;
    long long ans = 0;

    for (int i = 0; i < M; ++i) {
        long long X = pebbles[i].first;
        long long A = pebbles[i].second;

        if (X > current_pos) {
            cout << -1 << endl;
            return 0;
        }

        long long L = current_pos;
        long long R = current_pos + A - 1;

        long long start_offset = L - X;
        long long end_offset = R - X;

        ans += (start_offset + end_offset) * A / 2;

        current_pos = R + 1;
    }

    cout << ans << endl;

