char flip(char c) {
    if (c >= 'a' && c <= 'z') {
        return c - 'a' + 'A';
    } else {
        return c - 'A' + 'a';
    }
}

char solve(const string& M, long long K, int depth) {
    if (depth == 0) {
        return M[K - 1];
    }

    long long len = (long long)M.length() << depth;
    long long half = len / 2;

    if (K <= half) {
        return solve(M, K, depth - 1);
    } else {
        char c = solve(M, K - half, depth - 1);
        return flip(c);
    }
}

