def generate_sequences(P, Q):
    sequences = []

    def backtrack(current_sequence, position):
        if position == P:
            if current_sequence[-1] <= Q:
                sequences.append(current_sequence[:])
            return

        if position == 0:



            max_start = Q - 10 * (P - 1)
            for start in range(1, max_start + 1):
                current_sequence.append(start)
                backtrack(current_sequence, position + 1)
                current_sequence.pop()
        else:

            min_next = current_sequence[-1] + 10

            remaining_positions = P - position - 1
            max_next = Q - 10 * remaining_positions

            for next_val in range(min_next, max_next + 1):
                current_sequence.append(next_val)
                backtrack(current_sequence, position + 1)
                current_sequence.pop()

    backtrack([], 0)
    return sequences

