import (
	"bufio"
	"container/heap"
	"fmt"
	"os"
)

type Item struct {
	energy int64
	r, c   int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int           { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool { return pq[i].energy < pq[j].energy }
func (pq PriorityQueue) Swap(i, j int)      { pq[i], pq[j] = pq[j], pq[i] }

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var h, w int
	var x int64
	fmt.Fscan(reader, &h, &w, &x)

	var p, q int
	fmt.Fscan(reader, &p, &q)
	p--
	q--

	grid := make([][]int64, h)
	for i := 0; i < h; i++ {
		grid[i] = make([]int64, w)
		for j := 0; j < w; j++ {
			fmt.Fscan(reader, &grid[i][j])
		}
	}

	visited := make([][]bool, h)
	for i := 0; i < h; i++ {
		visited[i] = make([]bool, w)
	}

	astraEnergy := grid[p][q]
	visited[p][q] = true

	pq := &PriorityQueue{}
	heap.Init(pq)

	dr := []int{0, 0, 1, -1}
	dc := []int{1, -1, 0, 0}

	for i := 0; i < 4; i++ {
		nr, nc := p+dr[i], q+dc[i]
		if nr >= 0 && nr < h && nc >= 0 && nc < w {
			visited[nr][nc] = true
			heap.Push(pq, &Item{energy: grid[nr][nc], r: nr, c: nc})
		}
	}

	for pq.Len() > 0 {
		top := (*pq)[0]
		if top.energy < (astraEnergy+x-1)/x {
			item := heap.Pop(pq).(*Item)
			astraEnergy += item.energy
			for i := 0; i < 4; i++ {
				nr, nc := item.r+dr[i], item.c+dc[i]
				if nr >= 0 && nr < h && nc >= 0 && nc < w && !visited[nr][nc] {
					visited[nr][nc] = true
					heap.Push(pq, &Item{energy: grid[nr][nc], r: nr, c: nc})
				}
			}
		} else {
			break
		}
	}

	fmt.Println(astraEnergy)
}

