        }

        int maxTrees = 1;


        Set<Integer> heights = new HashSet<>();
        for (int i = 0; i < n; i++) {
            heights.add(h[i]);
        }

        for (int height : heights) {

            List<Integer> positions = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                if (h[i] == height) {
                    positions.add(i);
                }
            }


            for (int start = 0; start < positions.size(); start++) {
                for (int next = start + 1; next < positions.size(); next++) {
                    int interval = positions.get(next) - positions.get(start);
                    int count = 2;
                    int lastPos = positions.get(next);


                    for (int k = next + 1; k < positions.size(); k++) {
                        if (positions.get(k) - lastPos == interval) {
                            count++;
                            lastPos = positions.get(k);
                        }
                    }

                    maxTrees = Math.max(maxTrees, count);
                }
            }


            maxTrees = Math.max(maxTrees, Math.min(1, positions.size()));
        }

        System.out.println(maxTrees);
    }
