	var A, B string
	fmt.Scanf("%d", &M)
	fmt.Scanf("%s", &A)
	fmt.Scanf("%s", &B)

	n := len(A)
	m := len(B)


	dp := make([][]int, n+1)
	for i := range dp {
		dp[i] = make([]int, m+1)
		for j := range dp[i] {
			dp[i][j] = M + 1
		}
	}

	dp[0][0] = 0

	for i := 0; i <= n; i++ {
		for j := 0; j <= m; j++ {
			if dp[i][j] > M {
				continue
			}


			if j < m && dp[i][j+1] > dp[i][j]+1 {
				dp[i][j+1] = dp[i][j] + 1
			}


			if i < n && dp[i+1][j] > dp[i][j]+1 {
				dp[i+1][j] = dp[i][j] + 1
			}


			if i < n && j < m {
				cost := 0
				if A[i] != B[j] {
					cost = 1
				}
				if dp[i+1][j+1] > dp[i][j]+cost {
					dp[i+1][j+1] = dp[i][j] + cost
				}
			}
		}
	}

	if dp[n][m] <= M {
		fmt.Println("Yes")
	} else {
		fmt.Println("No")
	}
}

