class Solution:
    def maxPoints(self, m: int, t: int, restBonus: List[List[int]], switchBonus: List[List[int]]) -> int:
        dp = [[0] * m for _ in range(t + 1)]

        for day in range(t - 1, -1, -1):
            for arena in range(m):
                rest_points = restBonus[day][arena] + dp[day + 1][arena]

                switch_points = 0
                for dest in range(m):
                    if dest != arena:
                        switch_points = max(switch_points, switchBonus[arena][dest] + dp[day + 1][dest])

                dp[day][arena] = max(rest_points, switch_points)

        return max(dp[0])

