class Solution {
public:
    bool canJohnWin(int n) {
        int gems = n;
        int toExtract = 10;
        bool johnTurn = true;

        while (gems >= toExtract) {
            gems -= toExtract;
            toExtract--;
            johnTurn = !johnTurn;
        }

        return !johnTurn;
    }
};

