class Solution:
    def countBalancedQuadruplets(self, plants: list[int]) -> int:
        n = len(plants)
        if n < 7:
            return 0

        total_quadruplets = 0

        for c in range(4, n - 2):
            count_pairs = defaultdict(int)
            for a in range(c - 2):
                for b in range(a + 2, c - 1):
                    val = plants[a] * plants[c] / plants[b]
                    if val == int(val):
                        count_pairs[int(val)] += 1

            for d in range(c + 2, n):
                target = plants[d]
                if target in count_pairs:
                    total_quadruplets += count_pairs[target]

        return total_quadruplets

