def min_distance_circular(start, end, n, blocked):
    if start == end:
        return 0


    clockwise = 0
    pos = start
    valid_clockwise = True
    while pos != end:
        pos = pos % n + 1 if pos < n else 1
        clockwise += 1
        if pos == blocked and pos != end:
            valid_clockwise = False
            break


    counterclockwise = 0
    pos = start
    valid_counterclockwise = True
    while pos != end:
        pos = pos - 1 if pos > 1 else n
        counterclockwise += 1
        if pos == blocked and pos != end:
            valid_counterclockwise = False
            break

    if valid_clockwise and valid_counterclockwise:
        return min(clockwise, counterclockwise)
    elif valid_clockwise:
        return clockwise
    elif valid_counterclockwise:
        return counterclockwise
    else:
        return float('inf')

