using namespace std;

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 998244353;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 998244353;
        base = (base * base) % 998244353;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 998244353 - 2);
}

struct FenwickTree {
    int n;
    vector<int> tree;
    FenwickTree(int n) : n(n), tree(n + 1, 0) {}
    void add(int i, int val) {
        for (; i <= n; i += i & -i) tree[i] += val;
    }
    int query(int i) {
        int res = 0;
        for (; i > 0; i -= i & -i) res += tree[i];
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, K;
    cin >> N >> K;
    vector<int> S(N);
    for (int i = 0; i < N; ++i) cin >> S[i];

    if (K < 2) {
        long long inv_count = 0;
        FenwickTree ft(N);
        for (int i = N - 1; i >= 0; --i) {
            inv_count += ft.query(S[i] - 1);
            ft.add(S[i], 1);
        }
        cout << inv_count % 998244353 << endl;
        return 0;
    }

    long long initial_inv = 0;
    FenwickTree ft_init(N);
    for (int i = N - 1; i >= 0; --i) {
        initial_inv += ft_init.query(S[i] - 1);
        ft_init.add(S[i], 1);
    }
    initial_inv %= 998244353;

    long long total_delta = 0;
    long long current_window_inv = 0;
    FenwickTree ft_win(N);
    for (int i = 0; i < K; ++i) {
        current_window_inv += ft_win.query(N) - ft_win.query(S[i]);
        ft_win.add(S[i], 1);
    }

    long long k_pairs = (long long)K * (K - 1) / 2 % 998244353;
    long long expected_win_inv = k_pairs * modInverse(2) % 998244353;

    for (int i = 0; i <= N - K; ++i) {
        long long delta = (expected_win_inv - (current_window_inv % 998244353) + 998244353) % 998244353;
        total_delta = (total_delta + delta) % 998244353;

        if (i + K < N) {
            current_window_inv -= ft_win.query(S[i] - 1);
            ft_win.add(S[i], -1);
            current_window_inv += ft_win.query(N) - ft_win.query(S[i + K]);
            ft_win.add(S[i + K], 1);
        }
    }

    long long M = N - K + 1;
    long long ans = (initial_inv + total_delta * modInverse(M)) % 998244353;
    cout << ans << endl;

    return 0;
