func solve(operations [][]int) int {
	maxTime := 0
	bestSwitch := -1
	prevTime := 0

	for _, op := range operations {
		switchIdx := op[0]
		timestamp := op[1]
		duration := timestamp - prevTime

		if duration > maxTime {
			maxTime = duration
			bestSwitch = switchIdx
		} else if duration == maxTime {
			if bestSwitch == -1 || switchIdx < bestSwitch {
				bestSwitch = switchIdx
			}
		}
		prevTime = timestamp
	}

	return bestSwitch
}

