public class Solution {
    public int switchWithLongestTime(int[][] operations) {
        int maxTime = 0;
        int resultSwitch = -1;
        int lastTimestamp = 0;

        for (int i = 0; i < operations.length; i++) {
            int currentSwitch = operations[i][0];
            int currentTimestamp = operations[i][1];
            int duration = currentTimestamp - lastTimestamp;

            if (duration > maxTime) {
                maxTime = duration;
                resultSwitch = currentSwitch;
            } else if (duration == maxTime) {
                if (resultSwitch == -1 || currentSwitch < resultSwitch) {
                    resultSwitch = currentSwitch;
                }
            }
            lastTimestamp = currentTimestamp;
        }
        return resultSwitch;
    }

