        score = 0

        for i in range(n):
            reflection = get_reflection(t[i])

            for j in range(i - 1, -1, -1):
                if not marked[j] and t[j] == reflection:
                    marked[i] = True
                    marked[j] = True
                    score += i - j
                    break

