public class Solution {
    public long calculateReflectionScore(String t) {
        long totalScore = 0;
        Map<Character, Stack<Integer>> map = new HashMap<>();
        for (int i = 0; i < t.length(); i++) {
            char current = t.charAt(i);
            char reflection = (char) ('a' + ('z' - current));
            if (map.containsKey(reflection) && !map.get(reflection).isEmpty()) {
                int j = map.get(reflection).pop();
                totalScore += (i - j);
            } else {
                map.computeIfAbsent(current, k -> new Stack<>()).push(i);
            }
        }
        return totalScore;
    }

