	}
	invFact[n] = inverse(fact[n])
	for i := n - 1; i >= 0; i-- {
		invFact[i] = (invFact[i+1] * int64(i+1)) % MOD
	}

	comb := nCr(n-1, k, fact, invFact)
	waysToChooseColors := (int64(m) * power(int64(m-1), int64(n-1-k))) % MOD

	result := (comb * waysToChooseColors) % MOD
	fmt.Println(result)
}

