public class Solution {
    public int elegantDivisions(int[] elements) {
        int n = elements.length;
        int count = 0;

        for (int i = 1; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int[] elements1 = Arrays.copyOfRange(elements, 0, i);
                int[] elements2 = Arrays.copyOfRange(elements, i, j);
                int[] elements3 = Arrays.copyOfRange(elements, j, n);

                if (isPrefix(elements1, elements2) || isPrefix(elements2, elements3)) {
                    count++;
                }
            }
        }

        return count;
    }

    private boolean isPrefix(int[] prefix, int[] array) {
        if (prefix.length > array.length) {
            return false;
        }

        for (int i = 0; i < prefix.length; i++) {
            if (prefix[i] != array[i]) {
                return false;
            }
        }

        return true;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        String[] parts = line.substring(1, line.length() - 1).split(",");
        int[] elements = new int[parts.length];

        for (int i = 0; i < parts.length; i++) {
            elements[i] = Integer.parseInt(parts[i].trim());
        }

        Solution solution = new Solution();
        int result = solution.elegantDivisions(elements);
        System.out.println(result);
    }
}

class Solution {
public:
    int elegantDivisions(std::vector<int>& elements) {
        int n = elements.size();
        if (n < 3) return 0;
        int count = 0;
        for (int i = 1; i <= n - 2; ++i) {
            for (int j = i + 1; j <= n - 1; ++j) {
                int len1 = i;
                int len2 = j - i;
                int len3 = n - j;

                bool cond1 = false;
                if (len1 <= len2) {
                    bool match = true;
                    for (int k = 0; k < len1; ++k) {
                        if (elements[k] != elements[i + k]) {
                            match = false;
                            break;
                        }
                    }
                    if (match) cond1 = true;
                }

                if (cond1) {
                    count++;
                    continue;
                }

                bool cond2 = false;
                if (len2 <= len3) {
                    bool match = true;
                    for (int k = 0; k < len2; ++k) {
                        if (elements[i + k] != elements[j + k]) {
                            match = false;
                            break;
                        }
                    }
                    if (match) cond2 = true;
                }

                if (cond2) {
                    count++;
                }
            }
        }
        return count;
    }
};

