public class Solution {

    public int maxLength(int[] quantities) {
        int n = quantities.length;
        int maxLen = 0;

        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                if (isMetricBalanced(quantities, i, j)) {
                    maxLen = Math.max(maxLen, j - i + 1);
                }
            }
        }

        return maxLen;
    }

    private boolean isMetricBalanced(int[] arr, int start, int end) {
        long product = 1;
        int gcd = arr[start];
        int lcm = arr[start];

        for (int i = start; i <= end; i++) {
            product *= arr[i];
            gcd = gcd(gcd, arr[i]);
            lcm = lcm(lcm, arr[i]);
        }

        return product == (long) lcm * gcd;
    }

    private int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    private int lcm(int a, int b) {
        return (a / gcd(a, b)) * b;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        String[] parts = line.substring(1, line.length() - 1).split(",");
        int[] quantities = new int[parts.length];

        for (int i = 0; i < parts.length; i++) {
            quantities[i] = Integer.parseInt(parts[i].trim());
        }

        Solution solution = new Solution();
        int result = solution.maxLength(quantities);
        System.out.println(result);
    }
}

