public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] G = new int[N];
        int[] S = new int[N];
        int totalSum = 0;
        for (int i = 0; i < N; i++) {
            G[i] = sc.nextInt();
            S[i] = sc.nextInt();
            totalSum += S[i];
        }

        if (totalSum % 3 != 0) {
            System.out.println("-1");
            return;
        }

        int target = totalSum / 3;
        int[][] dp = new int[target + 1][target + 1];
        for (int i = 0; i <= target; i++) {
            Arrays.fill(dp[i], 1000);
        }
        dp[0][0] = 0;

        for (int i = 0; i < N; i++) {
            int skill = S[i];
            int group = G[i];
            int[][] nextDp = new int[target + 1][target + 1];
            for (int j = 0; j <= target; j++) {
                Arrays.fill(nextDp[j], 1000);
            }

            for (int s1 = 0; s1 <= target; s1++) {
                for (int s2 = 0; s2 <= target; s2++) {
                    if (dp[s1][s2] >= 1000) continue;

                    if (s1 + skill <= target) {
                        int cost = (group == 1) ? 0 : 1;
                        nextDp[s1 + skill][s2] = Math.min(nextDp[s1 + skill][s2], dp[s1][s2] + cost);
                    }

                    if (s2 + skill <= target) {
                        int cost = (group == 2) ? 0 : 1;
                        nextDp[s1][s2 + skill] = Math.min(nextDp[s1][s2 + skill], dp[s1][s2] + cost);
                    }

                    int s3 = totalSum - (s1 + s2);
                    if (s3 >= skill) {
                        int cost = (group == 3) ? 0 : 1;
                        nextDp[s1][s2] = Math.min(nextDp[s1][s2], dp[s1][s2] + cost);
                    }
                }
            }
            dp = nextDp;
        }

        int result = dp[target][target];
        if (result >= 1000) {
            System.out.println("-1");
        } else {
            System.out.println(result);
        }
    }
}

