    }


    clockwise := 0
    pos := from
    canGoClockwise := true
    for pos != to {
        pos++
        if pos > n {
            pos = 1
        }
        clockwise++
        if pos == blocked {
            canGoClockwise = false
            break
        }
    }


    counterclockwise := 0
    pos = from
    canGoCounterclockwise := true
    for pos != to {
        pos--
        if pos < 1 {
            pos = n
        }
        counterclockwise++
        if pos == blocked {
            canGoCounterclockwise = false
            break
        }
    }


    if canGoClockwise && canGoCounterclockwise {
        if clockwise < counterclockwise {
            return clockwise
        }
        return counterclockwise
    } else if canGoClockwise {
        return clockwise
    } else {
        return counterclockwise
    }
}

