public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();

        int leftPos = 1;
        int rightPos = 2;
        int totalOps = 0;

        for (int i = 0; i < Q; i++) {
            String H = sc.next();
            int T = sc.nextInt();

            if (H.equals("L")) {
                totalOps += minDistance(leftPos, T, rightPos, N);
                leftPos = T;
            } else {
                totalOps += minDistance(rightPos, T, leftPos, N);
                rightPos = T;
            }
        }

        System.out.println(totalOps);
    }

    static int minDistance(int from, int to, int blocked, int N) {
        if (from == to) return 0;


        int clockwise = 0;
        int pos = from;
        boolean canGoClockwise = true;

        while (pos != to) {
            pos = pos % N + 1;
            clockwise++;
            if (pos == blocked) {
                canGoClockwise = false;
                break;
            }
        }


        int counterclockwise = 0;
        pos = from;
        boolean canGoCounterclockwise = true;

        while (pos != to) {
            pos = pos == 1 ? N : pos - 1;
            counterclockwise++;
            if (pos == blocked) {
                canGoCounterclockwise = false;
                break;
            }
        }

        if (canGoClockwise && canGoCounterclockwise) {
            return Math.min(clockwise, counterclockwise);
        } else if (canGoClockwise) {
            return clockwise;
        } else {
            return counterclockwise;
        }
    }
}

def min_distance_circular(start, end, n, blocked):
    if start == end:
        return 0


    clockwise = 0
    pos = start
    valid_clockwise = True
    while pos != end:
        pos = pos % n + 1 if pos < n else 1
        clockwise += 1
        if pos == blocked and pos != end:
            valid_clockwise = False
            break


    counterclockwise = 0
    pos = start
    valid_counterclockwise = True
    while pos != end:
        pos = pos - 1 if pos > 1 else n
        counterclockwise += 1
        if pos == blocked and pos != end:
            valid_counterclockwise = False
            break

    if valid_clockwise and valid_counterclockwise:
        return min(clockwise, counterclockwise)
    elif valid_clockwise:
        return clockwise
    elif valid_counterclockwise:
        return counterclockwise
    else:
        return float('inf')

