func findShortestCycle(graph [][]int, n int) int {
	dist := make([]int, n+1)
	for i := range dist {
		dist[i] = -1
	}

	queue := []int{1}
	dist[1] = 0

	for len(queue) > 0 {
		curr := queue[0]
		queue = queue[1:]

		for _, next := range graph[curr] {
			if next == 1 && dist[curr] >= 0 {
				return dist[curr] + 1
			}

			if dist[next] == -1 {
				dist[next] = dist[curr] + 1
				queue = append(queue, next)
			}
		}
	}

	return -1
}

