struct Item {
    long long d, e;
};

bool compareItems(const Item& a, const Item& b) {
    return a.d < b.d;
}

void solve() {
    int N, K;
    if (!(cin >> N >> K)) return;
    vector<Item> items(N);
    for (int i = 0; i < N; ++i) cin >> items[i].d;
    for (int i = 0; i < N; ++i) cin >> items[i].e;

    sort(items.begin(), items.end(), compareItems);

    priority_queue<long long> pq;
    long long current_e_sum = 0;
    long long min_product = -1;

    for (int i = 0; i < N; ++i) {
        pq.push(items[i].e);
        current_e_sum += items[i].e;

        if (pq.size() > K) {
            current_e_sum -= pq.top();
            pq.pop();
        }

        if (pq.size() == K) {
            long long current_val = items[i].d * current_e_sum;
            if (min_product == -1 || current_val < min_product) {
                min_product = current_val;
            }
        }
    }

    cout << min_product << "\n";
}

