    if (!(cin >> N >> K)) return 0;

    vector<int> D(N + 1);
    for (int i = 1; i <= N; ++i) {
        cin >> D[i];
    }

    vector<int> result(N + 1);
    iota(result.begin(), result.end(), 0);

    vector<bool> visited(N + 1, false);
    for (int i = 1; i <= N; ++i) {
        if (!visited[i]) {
            vector<int> cycle;
            int curr = i;
            while (!visited[curr]) {
                visited[curr] = true;
                cycle.push_back(curr);
                curr = D[curr];
            }

            int len = cycle.size();
            long long steps = 1;
            long long base = 2;
            long long k_temp = K;
            while (k_temp > 0) {
                if (k_temp & 1) steps = (steps * base) % len;
                base = (base * base) % len;
                k_temp >>= 1;
            }

            for (int j = 0; j < len; ++j) {
                result[cycle[j]] = cycle[(j + steps) % len];
            }
        }
    }

    for (int i = 1; i <= N; ++i) {
        cout << result[i] << (i == N ? "" : " ");
    }
    cout << endl;

    return 0;
