        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        sc.nextLine();

        String[] docs = new String[n];
        for (int i = 0; i < n; i++) {
            docs[i] = sc.nextLine();
        }

        for (int k = 0; k < n; k++) {
            String current = docs[k];
            int minCost = current.length();


            for (int i = 0; i < k; i++) {
                String target = docs[i];
                int cost = transformCost(current, target);
                minCost = Math.min(minCost, cost);
            }

            System.out.println(minCost);
        }
    }

    static int transformCost(String from, String to) {
        int commonPrefix = 0;
        int minLen = Math.min(from.length(), to.length());

        for (int i = 0; i < minLen; i++) {
            if (from.charAt(i) == to.charAt(i)) {
                commonPrefix++;
            } else {
                break;
            }
        }

        int deletions = from.length() - commonPrefix;
        int additions = to.length() - commonPrefix;

        return deletions + additions;
    }
}

