func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n int
	fmt.Fscan(reader, &n)

	docs := make([]string, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &docs[i])
	}

	trie := make([]Node, 1)
	trie[0].depth = 0
	for i := 0; i < 26; i++ {
		trie[0].children[i] = -1
	}

	dp := make([]int, 1)
	dp[0] = 0

	for k := 0; k < n; k++ {
		s := docs[k]
		path := make([]int, len(s)+1)
		curr := 0
		path[0] = curr

		for i := 0; i < len(s); i++ {
			charIdx := int(s[i] - 'a')
			if trie[curr].children[charIdx] == -1 {
				newNodeIdx := len(trie)
				trie[curr].children[charIdx] = newNodeIdx
				newNode := Node{depth: trie[curr].depth + 1}
				for j := 0; j < 26; j++ {
					newNode.children[j] = -1
				}
				trie = append(trie, newNode)
				dp = append(dp, 1000000000)
			}
			curr = trie[curr].children[charIdx]
			path[i+1] = curr
		}

		ans := len(s)
		for i := 0; i <= len(s); i++ {
			cost := (len(s) - i) + dp[path[i]]
			if cost < ans {
				ans = cost
			}
		}

		fmt.Fprintln(writer, ans)

		curr = 0
		for i := 0; i <= len(s); i++ {
			nodeIdx := path[i]
			dist := len(s) - i
			if dist < dp[nodeIdx] {
				dp[nodeIdx] = dist
			}
		}
	}
}

import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    docs = input_data[1:]

    class TrieNode:
        __slots__ = ['children', 'min_depth']
        def __init__(self):
            self.children = {}
            self.min_depth = float('inf')

    root = TrieNode()
    results = []

    for k in range(n):
        s = docs[k]
        l = len(s)

        if k == 0:
            results.append(l)
        else:
            ans = l
            curr = root
            for i, char in enumerate(s):
                if char in curr.children:
                    curr = curr.children[char]
                    ans = min(ans, (l - (i + 1)) + curr.min_depth)
                else:
                    break
            results.append(ans)

        curr = root
        for i, char in enumerate(s):
            if char not in curr.children:
                curr.children[char] = TrieNode()
            curr = curr.children[char]
            curr.min_depth = min(curr.min_depth, l - (i + 1))

    sys.stdout.write('\n'.join(map(str, results)) + '\n')

