bool canSee(const vector<int>& H, int from, int to) {
    if (from >= to) return false;
    int targetHeight = H[to];
    for (int k = from + 1; k < to; k++) {
        if (H[k] > targetHeight) {
            return false;
        }
    }
    return true;
}

