const int INF = 1e9;

struct Node {
    int min_val;
};

vector<Node> tree;
int n_size;

void build(const vector<int>& S, int node, int start, int end) {
    if (start == end) {
        tree[node] = {S[start]};
        return;
    }
    int mid = (start + end) / 2;
    build(S, 2 * node, start, mid);
    build(S, 2 * node + 1, mid + 1, end);
    tree[node].min_val = min(tree[2 * node].min_val, tree[2 * node + 1].min_val);
}

int query(int node, int start, int end, int val) {
    if (tree[node].min_val > val) return -1;
    if (start == end) return start + 1;
    int mid = (start + end) / 2;
    if (tree[2 * node].min_val <= val) {
        return query(2 * node, start, mid, val);
    } else {
        return query(2 * node + 1, mid + 1, end, val);
    }
}

