        if (current.size() == P) {
            if (current.get(P - 1) <= Q) {
                results.add(new ArrayList<>(current));
            }
            return;
        }

        int maxPossible = Q - 10 * (P - current.size() - 1);

        for (int val = minVal; val <= maxPossible; val++) {
            current.add(val);
            backtrack(current, val + 10);
            current.remove(current.size() - 1);
        }
    }
