        for (int j = 0; j < N; j++) {
            if (grid[i][j] == '.') {
                open_cells.push_back({i, j});
            }
        }
    }

    int max_covered = 0;
    int n_open = open_cells.size();

    for (int i = 0; i < n_open; i++) {
        for (int j = i + 1; j < n_open; j++) {
            int r1_x = open_cells[i].first;
            int r1_y = open_cells[i].second;
            int r2_x = open_cells[j].first;
            int r2_y = open_cells[j].second;

