                int dist1 = abs(x - r1_x) + abs(y - r1_y);
                int dist2 = abs(x - r2_x) + abs(y - r2_y);

                if (dist1 <= R || dist2 <= R) {
                    covered++;
                }
            }

            max_covered = max(max_covered, covered);
        }
