func sieve(n int) []int {
	isPrime := make([]bool, n+1)
	for i := 2; i <= n; i++ {
		isPrime[i] = true
	}

	for i := 2; i*i <= n; i++ {
		if isPrime[i] {
			for j := i * i; j <= n; j += i {
				isPrime[j] = false
			}
		}
	}

	var primes []int
	for i := 2; i <= n; i++ {
		if isPrime[i] {
			primes = append(primes, i)
		}
	}
	return primes
}

func main() {
	var L int64
	fmt.Scan(&L)

	limit := int(math.Sqrt(float64(L))) + 1
	primes := sieve(limit)

	count := int64(0)


	for _, p := range primes {
		p8 := int64(1)
		for i := 0; i < 8; i++ {
			if p8 > L/int64(p) {
				p8 = L + 1
				break
			}
			p8 *= int64(p)
		}
		if p8 <= L {
			count++
		}
	}


	for i := 0; i < len(primes); i++ {
		p := int64(primes[i])
		p2 := p * p
		if p2 > L {
			break
		}
		for j := i + 1; j < len(primes); j++ {
			q := int64(primes[j])
			q2 := q * q
			if p2 > L/q2 {
				break
			}
			count++
		}
	}

	fmt.Println(count)
}

