func main() {
	var N int
	var S int64
	fmt.Scan(&N, &S)

	L := make([]int64, N)
	for i := 0; i < N; i++ {
		fmt.Scan(&L[i])
	}



	extended := make([]int64, 2*N)
	for i := 0; i < N; i++ {
		extended[i] = L[i]
		extended[i+N] = L[i]
	}


	found := false


	for length := 1; length <= 2*N && !found; length++ {
		sum := int64(0)

		for i := 0; i < length; i++ {
			sum += extended[i]
		}
		if sum == S {
			found = true
			break
		}


		for start := 1; start <= 2*N-length && !found; start++ {
			sum = sum - extended[start-1] + extended[start+length-1]
			if sum == S {
				found = true
				break
			}
		}
	}


	if !found {
		cycleSum := int64(0)
		for i := 0; i < N; i++ {
			cycleSum += L[i]
		}

		if cycleSum > 0 {

			for start := 0; start < N && !found; start++ {
				sum := int64(0)
				for end := start; end < start+N && !found; end++ {
					sum += L[end%N]
					if sum <= S && (S-sum)%cycleSum == 0 && (S-sum)/cycleSum >= 0 {
						found = true
					}
				}
			}
		}
	}

	if found {
		fmt.Println("Yes")
	} else {
		fmt.Println("No")
	}
}

