		return
	}

	posMap := make(map[int][]int)
	for i := 0; i < n; i++ {
		posMap[h[i]] = append(posMap[h[i]], i)
	}

	maxCount := 1

	for _, indices := range posMap {
		m := len(indices)
		if m <= maxCount {
			continue
		}

		dp := make([][]int, m)
		for i := range dp {
			dp[i] = make([]int, m)
			for j := range dp[i] {
				dp[i][j] = 2
			}
		}

		idxToPos := make(map[int]int)
		for i, val := range indices {
			idxToPos[val] = i
		}

		for j := 0; j < m; j++ {
			for i := 0; i < j; i++ {
				diff := indices[j] - indices[i]
				prevVal := indices[i] - diff

				if prevVal < indices[0] {
					if dp[i][j] > maxCount {
						maxCount = dp[i][j]
					}
					continue
				}

				if k, ok := idxToPos[prevVal]; ok {
					dp[i][j] = dp[k][i] + 1
				}

				if dp[i][j] > maxCount {
					maxCount = dp[i][j]
				}
			}
		}
	}

	fmt.Println(maxCount)
