        m = len(indices)
        if m <= max_count:
            continue

        dp = [{} for _ in range(m)]
        for i in range(m):
            for j in range(i):
                diff = indices[i] - indices[j]
                count = dp[j].get(diff, 1) + 1
                dp[i][diff] = count
                if count > max_count:
                    max_count = count

    print(max_count)

