        adj[u].push_back(v);
        adj[v].push_back(u);
        degree[u]++;
        degree[v]++;
    }

    if (N < 3) {
        cout << 0 << endl;
        return 0;
    }

    int max_nodes = 0;

    for (int c = 1; c <= N; ++c) {
        if (adj[c].size() < 1) continue;

        int current_total = 1;
        vector<int> neighbor_gains;

        for (int v : adj[c]) {
            int d_v = degree[v];
            if (d_v >= 2) {
                neighbor_gains.push_back(d_v - 1);
            }
        }

        if (neighbor_gains.empty()) continue;

        sort(neighbor_gains.begin(), neighbor_gains.end(), greater<int>());

        int current_sum = 0;
