            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
    }

    static boolean canTransform(String P, String Q) {
        int pLen = P.length();
        int qLen = Q.length();


        if (P.equals(Q)) {
            return true;
        }


        if (pLen == qLen) {
            int diff = 0;
            for (int i = 0; i < pLen; i++) {
                if (P.charAt(i) != Q.charAt(i)) {
                    diff++;
                    if (diff > 1) return false;
                }
            }
            return diff == 1;
        }


        if (pLen == qLen + 1) {
            for (int i = 0; i < pLen; i++) {
                String modified = P.substring(0, i) + P.substring(i + 1);
                if (modified.equals(Q)) {
                    return true;
                }
            }
            return false;
        }


        if (pLen == qLen - 1) {
            for (int i = 0; i <= pLen; i++) {
                for (char c = 'a'; c <= 'z'; c++) {
                    String modified = P.substring(0, i) + c + P.substring(i);
                    if (modified.equals(Q)) {
                        return true;
                    }
                }
            }
            return false;
        }


        return false;
    }
}

