            odd_diffs.push_back(diffs[i]);
        }
    }

    sort(even_diffs.begin(), even_diffs.end());
    sort(odd_diffs.begin(), odd_diffs.end());

    vector<long long> final_diffs(N - 1);
    int e_ptr = 0, o_ptr = 0;
    for (int i = 0; i < N - 1; ++i) {
        if (i % 2 == 0) {
            final_diffs[i] = even_diffs[e_ptr++];
        } else {
            final_diffs[i] = odd_diffs[o_ptr++];
        }
    }

    vector<long long> final_P(N);
    final_P[0] = P[0];
    for (int i = 0; i < N - 1; ++i) {
        final_P[i + 1] = final_P[i] + final_diffs[i];
    }

    long long total_sum = 0;
    for (int i = 0; i < N; ++i) {
        total_sum += final_P[i];
    }

    cout << total_sum << endl;

