long long solve(vector<long long> a, int k) {
    int n = a.size();
    int pos = k;
    long long jordan_size = a[k];

    while (true) {
        bool absorbed = false;


        if (pos > 0 && a[pos-1] < jordan_size) {
            jordan_size += a[pos-1];
            a.erase(a.begin() + pos - 1);
            pos--;
            absorbed = true;
        }

        else if (pos < a.size() - 1 && a[pos+1] < jordan_size) {
            jordan_size += a[pos+1];
            a.erase(a.begin() + pos + 1);
            absorbed = true;
        }

        if (!absorbed) break;
        a[pos] = jordan_size;
    }

    return jordan_size;
}

