import sys
import json
from typing import List

class Solution:
    def rotateCost(self, g: str, h: str, forwardCost: List[int], backwardCost: List[int]) -> int:
        dist = [[float('inf')] * 26 for _ in range(26)]
        for i in range(26):
            dist[i][i] = 0
            dist[i][(i + 1) % 26] = min(dist[i][(i + 1) % 26], forwardCost[i])
            dist[i][(i - 1 + 26) % 26] = min(dist[i][(i - 1 + 26) % 26], backwardCost[i])

        for k in range(26):
            for i in range(26):
                for j in range(26):
                    if dist[i][k] + dist[k][j] < dist[i][j]:
                        dist[i][j] = dist[i][k] + dist[k][j]

        total_cost = 0
        for char_g, char_h in zip(g, h):
            u = ord(char_g) - ord('a')
            v = ord(char_h) - ord('a')
            total_cost += dist[u][v]

        return int(total_cost)

def main():
    input_data = sys.stdin.read().splitlines()
    if not input_data:
        return

    g = json.loads(input_data[0])
    h = json.loads(input_data[1])
    forwardCost = json.loads(input_data[2])
    backwardCost = json.loads(input_data[3])

    sol = Solution()
    result = sol.rotateCost(g, h, forwardCost, backwardCost)
    print(result)

if __name__ == "__main__":
    main()

