public class Solution {

    public static long gcd(long a, long b) {
        while (b != 0) {
            long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    public static long lcm(long a, long b) {
        return (a * b) / gcd(a, b);
    }

    public static long calculateGCD(int[] arr) {
        if (arr.length == 0) return 0;
        long result = arr[0];
        for (int i = 1; i < arr.length; i++) {
            result = gcd(result, arr[i]);
        }
        return result;
    }

    public static long calculateLCM(int[] arr) {
        if (arr.length == 0) return 0;
        long result = arr[0];
        for (int i = 1; i < arr.length; i++) {
            result = lcm(result, arr[i]);
        }
        return result;
    }

    public static long calculateMaximumCompositeStrength(int[] strengths) {
        int n = strengths.length;
        if (n == 0) return 0;

        long maxStrength = 0;


        long gcdAll = calculateGCD(strengths);
        long lcmAll = calculateLCM(strengths);
        maxStrength = Math.max(maxStrength, gcdAll * lcmAll);


        for (int i = 0; i < n; i++) {
            int[] remaining = new int[n - 1];
            int idx = 0;
            for (int j = 0; j < n; j++) {
                if (j != i) {
                    remaining[idx++] = strengths[j];
                }
            }

            if (remaining.length == 0) {
                maxStrength = Math.max(maxStrength, 0);
            } else {
                long gcdRemaining = calculateGCD(remaining);
                long lcmRemaining = calculateLCM(remaining);
                maxStrength = Math.max(maxStrength, gcdRemaining * lcmRemaining);
            }
        }

        return maxStrength;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

