using namespace std;

class Solution {
public:
    int findMaximumAnomaly(vector<int>& values) {
        long long total_sum = 0;
        unordered_map<int, int> counts;
        for (int x : values) {
            total_sum += x;
            counts[x]++;
        }

        int max_anomaly = -2001;
        int n = values.size();

        for (int i = 0; i < n; ++i) {
            int current_val = values[i];
            long long remaining_sum = total_sum - current_val;
            counts[current_val]--;
            if (counts[current_val] == 0) counts.erase(current_val);

            for (auto const& [val, count] : counts) {
                if ((remaining_sum - val) == (long long)val) {
                    max_anomaly = max(max_anomaly, current_val);
                    break;
                }
            }

            counts[current_val]++;
        }

        return max_anomaly;
    }
};

int main() {
    vector<int> values;
    int val;
    char ch;

    while (cin >> ch && ch != '[') {}
    while (cin >> val) {
        values.push_back(val);
        if (!(cin >> ch) || ch == ']') break;
    }

    Solution sol;
    cout << sol.findMaximumAnomaly(values) << endl;

    return 0;
}

