		return
	}
	if err := dec.Decode(&pairs2); err != nil {
		return
	}
	if err := dec.Decode(&rates2); err != nil {
		return
	}

	day1Map := getMaxRates(initialResource, pairs1, rates1)

	maxResult := 0.0
	for resource, amount := range day1Map {
		day2Map := getMaxRates(resource, pairs2, rates2)
		if finalAmount, ok := day2Map[initialResource]; ok {
			val := amount * finalAmount
			if val > maxResult {
				maxResult = val
			}
		}
	}

	fmt.Printf("%.5f\n", maxResult)
}

func getMaxRates(startNode string, pairs [][]string, rates []float64) map[string]float64 {
	adj := make(map[string]map[string]float64)
	nodes := make(map[string]bool)
	for i, pair := range pairs {
		u, v := pair[0], pair[1]
		r := rates[i]
		if adj[u] == nil {
			adj[u] = make(map[string]float64)
		}
		if adj[v] == nil {
			adj[v] = make(map[string]float64)
		}
		adj[u][v] = r
		adj[v][u] = 1.0 / r
		nodes[u] = true
		nodes[v] = true
	}
	nodes[startNode] = true

	dist := make(map[string]float64)
	for n := range nodes {
		dist[n] = 0.0
	}
	dist[startNode] = 1.0

	for i := 0; i < len(nodes); i++ {
		changed := false
		for u, targets := range adj {
			for v, r := range targets {
				if dist[u] > 0 && dist[u]*r > dist[v] {
					dist[v] = dist[u] * r
					changed = true
				}
			}
		}
		if !changed {
			break
		}
	}
	return dist
}

