package main

import (
	"bufio"
	"container/heap"
	"encoding/json"
	"fmt"
	"os"
)

type MaxHeap []int

func (h MaxHeap) Len() int           { return len(h) }
func (h MaxHeap) Less(i, j int) bool { return h[i] > h[j] }
func (h MaxHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MaxHeap) Push(x interface{}) {
	*h = append(*h, x.(int))
}
func (h *MaxHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

type FenwickTree struct {
	tree []int
	n    int
}

func NewFenwickTree(n int) *FenwickTree {
	return &FenwickTree{tree: make([]int, n+1), n: n}
}

func (f *FenwickTree) Update(i int, val int) {
	for i <= f.n {
		f.tree[i] += val
		i += i & -i
	}
}

func (f *FenwickTree) Query(i int) int {
	sum := 0
	for i > 0 {
		sum += f.tree[i]
		i -= i & -i
	}
	return sum
}

func solve() {
	reader := bufio.NewReader(os.Stdin)
	var stock []int
	var operations [][]int

	input, _ := reader.ReadString('\n')
	if input == "" {
		return
	}
	json.Unmarshal([]byte(input), &stock)

	input, _ = reader.ReadString('\n')
	json.Unmarshal([]byte(input), &operations)

	n := len(stock)
	m := len(operations)

	opsAt := make([][]int, n)
	for i := 0; i < m; i++ {
		opsAt[operations[i][0]] = append(opsAt[operations[i][0]], operations[i][1])
	}

	ft := NewFenwickTree(n + 1)
	maxHeap := &MaxHeap{}
	heap.Init(maxHeap)

	removed := 0
	for i := 0; i < n; i++ {
		for _, end := range opsAt[i] {
			heap.Push(maxHeap, end)
		}

		currentStock := stock[i] - ft.Query(i+1)
		for currentStock > 0 {
			if maxHeap.Len() == 0 {
				fmt.Println("-1")
				return
			}
			topEnd := heap.Pop(maxHeap).(int)
			if topEnd < i {
				continue
			}
			ft.Update(i+1, 1)
			ft.Update(topEnd+2, -1)
			currentStock--
			removed++
		}
	}

	fmt.Println(m - removed)
}

func main() {
	solve()
}

