                if val1 >= k:
                    val_both2 = val1 - k
                    options.append(val_both2 + solve(i + 1, o1 - 1, o2 - 1))

            result = min(options)
            dp[(i, o1, o2)] = result
            return result

        return solve(0, op1, op2)

