from typing import List
import math

class Solution:
    def maxLength(self, quantities: List[int]) -> int:
        def gcd_list(arr):
            result = arr[0]
            for i in range(1, len(arr)):
                result = math.gcd(result, arr[i])
            return result

        def lcm_list(arr):
            result = arr[0]
            for i in range(1, len(arr)):
                result = (result * arr[i])
            return result

        def product(arr):
            result = 1
            for num in arr:
                result *= num
            return result

        n = len(quantities)
        max_length = 0

        for i in range(n):
            for j in range(i, n):
                subseq = quantities[i:j+1]
                prod = product(subseq)
                gcd_val = gcd_list(subseq)
                lcm_val = lcm_list(subseq)

                if prod == lcm_val * gcd_val:
                    max_length = max(max_length, len(subseq))

        return max_length

def main():
    line = input().strip()
    quantities = list(map(int, line.split()))
    solution = Solution()
    result = solution.maxLength(quantities)
    print(result)

main()

