using namespace std;

const int INF = 1e9;

int main() {
    int N;
    if (!(cin >> N)) return 0;

    vector<int> G(N), S(N);
    int total_skill = 0;
    for (int i = 0; i < N; ++i) {
        cin >> G[i] >> S[i];
        total_skill += S[i];
    }

    if (total_skill % 3 != 0) {
        cout << -1 << endl;
        return 0;
    }

    int target = total_skill / 3;
    vector<vector<int>> dp(target + 1, vector<int>(target + 1, INF));
    dp[0][0] = 0;

    for (int i = 0; i < N; ++i) {
        vector<vector<int>> next_dp(target + 1, vector<int>(target + 1, INF));
        for (int s1 = 0; s1 <= target; ++s1) {
            for (int s2 = 0; s2 <= target; ++s2) {
                if (dp[s1][s2] == INF) continue;

                for (int g = 1; g <= 3; ++g) {
                    int ns1 = s1, ns2 = s2;
                    if (g == 1) ns1 += S[i];
                    else if (g == 2) ns2 += S[i];

                    if (ns1 <= target && ns2 <= target) {
                        int cost = (G[i] == g ? 0 : 1);
                        next_dp[ns1][ns2] = min(next_dp[ns1][ns2], dp[s1][s2] + cost);
                    }
                }
            }
        }
        dp = move(next_dp);
    }

    if (dp[target][target] >= INF) {
        cout << -1 << endl;
    } else {
        cout << dp[target][target] << endl;
    }

    return 0;
}

