import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    ptr = 0
    N = int(input_data[ptr])
    M = int(input_data[ptr+1])
    Q = int(input_data[ptr+2])
    ptr += 3

    edges = []
    for _ in range(M):
        u = int(input_data[ptr]) - 1
        v = int(input_data[ptr+1]) - 1
        w = int(input_data[ptr+2])
        edges.append([u, v, w])
        ptr += 3

    queries = []
    removed_edge_indices = set()
    for _ in range(Q):
        type = int(input_data[ptr])
        if type == 1:
            idx = int(input_data[ptr+1]) - 1
            queries.append((1, idx))
            removed_edge_indices.add(idx)
            ptr += 2
        else:
            u = int(input_data[ptr+1]) - 1
            v = int(input_data[ptr+2]) - 1
            queries.append((2, u, v))
            ptr += 3

    inf = float('inf')
    dist = [[inf] * N for _ in range(N)]
    for i in range(N):
        dist[i][i] = 0

    for i in range(M):
        if i not in removed_edge_indices:
            u, v, w = edges[i]
            if w < dist[u][v]:
                dist[u][v] = dist[v][u] = w

    for k in range(N):
        dk = dist[k]
        for i in range(N):
            di = dist[i]
            if di[k] == inf:
                continue
            for j in range(N):
                if di[j] > di[k] + dk[j]:
                    di[j] = di[k] + dk[j]

    results = []
    rev_queries = queries[::-1]
    for q in rev_queries:
        if q[0] == 1:
            idx = q[1]
            u, v, w = edges[idx]
            if w < dist[u][v]:
                dist[u][v] = dist[v][u] = w
                for i in range(N):
                    di = dist[i]
                    if di[u] == inf:
                        continue
                    for j in range(N):
                        if di[j] > di[u] + w + dist[v][j]:
                            di[j] = di[u] + w + dist[v][j]
                for i in range(N):
                    di = dist[i]
                    if di[v] == inf:
                        continue
                    for j in range(N):
                        if di[j] > di[v] + w + dist[u][j]:
                            di[j] = di[v] + w + dist[u][j]
        else:
            u, v = q[1], q[2]
            res = dist[u][v]
            results.append(res if res != inf else -1)

    sys.stdout.write('\n'.join(map(str, results[::-1])) + '\n')

if __name__ == '__main__':
    solve()

