using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    long long N;
    int M;
    if (!(cin >> N >> M)) return 0;

    set<long long> rows, cols, diag1, diag2;
    for (int i = 0; i < M; ++i) {
        long long r, c;
        cin >> r >> c;
        rows.insert(r);
        cols.insert(c);
        diag1.insert(r + c);
        diag2.insert(r - c);
    }

    vector<long long> row_vec(rows.begin(), rows.end());
    vector<long long> col_vec(cols.begin(), cols.end());
    vector<long long> d1_vec(diag1.begin(), diag1.end());
    vector<long long> d2_vec(diag2.begin(), diag2.end());

    long long total_cells = N * N;
    long long row_count = row_vec.size();
    long long col_count = col_vec.size();

    long long covered = row_count * N + col_count * N - row_count * col_count;

    auto is_in_grid = [&](long long r, long long c) {
        return r >= 1 && r <= N && c >= 1 && c <= N;
    };

    auto is_covered_by_rc = [&](long long r, long long c) {
        return rows.count(r) || cols.count(c);
    };

    for (long long s : d1_vec) {
        long long min_r = max(1LL, s - N);
        long long max_r = min(N, s - 1);
        if (min_r <= max_r) {
            long long count = max_r - min_r + 1;
            for (long long r : row_vec) {
                if (r >= min_r && r <= max_r) count--;
            }
            for (long long c : col_vec) {
                long long r = s - c;
                if (r >= min_r && r <= max_r && !rows.count(r)) count--;
            }
            covered += count;
        }
    }

    for (long long d : d2_vec) {
        long long min_r = max(1LL, 1 + d);
        long long max_r = min(N, N + d);
        if (min_r <= max_r) {
            long long count = max_r - min_r + 1;
            for (long long r : row_vec) {
                if (r >= min_r && r <= max_r) count--;
            }
            for (long long c : col_vec) {
                long long r = d + c;
                if (r >= min_r && r <= max_r && !rows.count(r)) count--;
            }
            for (long long s : d1_vec) {
                if ((s + d) % 2 == 0) {
                    long long r = (s + d) / 2;
                    long long c = (s - d) / 2;
                    if (r >= min_r && r <= max_r && !is_covered_by_rc(r, c)) count--;
                }
            }
            covered += count;
        }
    }

    cout << total_cells - covered << endl;

    return 0;
}

