	"fmt"
	"math/big"
	"os"
)

func main() {
	var m int
	fmt.Scan(&m)

	reader := bufio.NewReader(os.Stdin)
	c, _ := reader.ReadString('\n')
	if len(c) > 0 && c[len(c)-1] == '\n' {
		c = c[:len(c)-1]
	}
	if len(c) > 0 && c[len(c)-1] == '\r' {
		c = c[:len(c)-1]
	}

	total := big.NewInt(0)
	currentDigitContribution := big.NewInt(0)
	ten := big.NewInt(10)

	for i := 0; i < m; i++ {
		digit := int64(c[i] - '0')

		term1 := new(big.Int).Mul(currentDigitContribution, ten)

		term2 := big.NewInt(int64(i + 1))
		term2.Mul(term2, big.NewInt(digit))

		currentDigitContribution.Add(term1, term2)
		total.Add(total, currentDigitContribution)
	}

	fmt.Println(total.String())
}

