import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    k = int(input_data[1])
    c = input_data[2]

    segments = []
    i = 0
    while i < n:
        if c[i] == 'Y':
            start = i
            while i < n and c[i] == 'Y':
                i += 1
            segments.append((start, i - 1))
        else:
            i += 1

    if k == 1:
        print(c)
        return

    lk_minus_1, rk_minus_1 = segments[k-2]
    lk, rk = segments[k-1]

    len_k = rk - lk + 1

    res = list(c)

    for idx in range(rk_minus_1 + 1, rk_minus_1 + 1 + len_k):
        res[idx] = 'Y'

    for idx in range(rk_minus_1 + 1 + len_k, rk + 1):
        res[idx] = 'X'

    print("".join(res))

def main():
    solve()

if __name__ == "__main__":
    main()

