def flip_case(c):
    if c.islower():
        return c.upper()
    else:
        return c.lower()

def find_char(original, k, level):
    if level == 0:
        return original[k-1]

    length = len(original) * (2 ** level)
    half_length = length

    if k <= half_length:
        return find_char(original, k, level - 1)
    else:
        char = find_char(original, k - half_length, level - 1)
        return flip_case(char)

def main():
    M = input().strip()
    Q = int(input().strip())
    queries = list(map(int, input().strip().split()))

    results = []

    for k in queries:
        level = 0
        current_length = len(M)

        while current_length < k:
            current_length *= 2
            level += 1

        char = find_char(M, k, level)
        results.append(char)

    print(' '.join(results))

main()

