def main():
    N, Q = map(int, input().split())


    plots = [0] + list(range(1, N + 1))

    for _ in range(Q):
        query = list(map(int, input().split()))

        if query[0] == 1:
            x, c = query[1], query[2]
            original_type = plots[x]

            if original_type != c:

                to_change = []
                visited = [False] * (N + 1)
                stack = [x]

                while stack:
                    pos = stack.pop()
                    if visited[pos]:
                        continue
                    visited[pos] = True
                    to_change.append(pos)


                    if pos > 1 and not visited[pos - 1] and plots[pos - 1] == original_type:
                        stack.append(pos - 1)


                    if pos < N and not visited[pos + 1] and plots[pos + 1] == original_type:
                        stack.append(pos + 1)


                for pos in to_change:
                    plots[pos] = c

        else:
            c = query[1]
            count = sum(1 for i in range(1, N + 1) if plots[i] == c)
            print(count)

main()

