                count[d[end]] = 0
            count[d[end]] += 1


            length = end - start + 1
            if length % 2 == 0:

                valid_pairs = True
                for i in range(start, end + 1, 2):
                    if d[i] != d[i + 1]:
                        valid_pairs = False
