                if valid_pairs:

                    valid_counts = True
                    for cnt in count.values():
                        if cnt != 2:
                            valid_counts = False
                            break

                    if valid_counts:
                        max_length = max(max_length, length)


            if any(cnt > 2 for cnt in count.values()):
                break

    print(max_length)

