def main():
    M, N, R = map(int, input().split())
    grid = []
    for _ in range(M):
        grid.append(input().strip())


    open_cells = []
    for i in range(M):
        for j in range(N):
            if grid[i][j] == '.':
                open_cells.append((i, j))

    max_covered = 0


    for i in range(len(open_cells)):
        for j in range(i + 1, len(open_cells)):
            router1 = open_cells[i]
            router2 = open_cells[j]

            covered = 0

            for cell in open_cells:
                x, y = cell
                x1, y1 = router1
                x2, y2 = router2

                dist1 = abs(x - x1) + abs(y - y1)
                dist2 = abs(x - x2) + abs(y - y2)

                if dist1 <= R or dist2 <= R:
                    covered += 1

            max_covered = max(max_covered, covered)

    print(max_covered)

main()

