    for p in range(2, n + 1):
        if is_prime[p]:
            primes.append(p)
            for i in range(p * p, n + 1, p):
                is_prime[i] = False
    return primes

def main():
    line = sys.stdin.readline()
    if not line:
        return
    L = int(line.strip())

    ans = 0

    limit_p8 = int(L**(1/8)) + 2
    primes_p8 = get_primes(limit_p8)
    for p in primes_p8:
        if p**8 <= L:
            ans += 1

    limit_pq = int(L**0.5) + 2
    primes = get_primes(limit_pq)

    n = len(primes)
    for i in range(n):
        p_sq = primes[i]**2
        if p_sq * (primes[i+1]**2 if i+1 < n else float('inf')) > L:
            break
        for j in range(i + 1, n):
            if p_sq * (primes[j]**2) <= L:
                ans += 1
            else:
                break

    print(ans)

if __name__ == "__main__":
    main()

