import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    h = list(map(int, input_data[1:]))

    pos_map = {}
    for i in range(n):
        val = h[i]
        if val not in pos_map:
            pos_map[val] = []
        pos_map[val].append(i)

    max_count = 1
    for val in pos_map:
        indices = pos_map[val]
        m = len(indices)
        if m <= max_count:
            continue

        dp = [{} for _ in range(m)]
        for i in range(m):
            for j in range(i):
                diff = indices[i] - indices[j]
                count = dp[j].get(diff, 1) + 1
                dp[i][diff] = count
                if count > max_count:
                    max_count = count

    print(max_count)

def main():
    solve()

if __name__ == "__main__":
    main()

