def main():
    n = int(input())

    if n == 1:
        print(0)
        return

    adj = [[] for _ in range(n + 1)]

    for _ in range(n - 1):
        u, v = map(int, input().split())
        adj[u].append(v)
        adj[v].append(u)

    max_galaxy_size = 0


    for center in range(1, n + 1):
        neighbors = adj[center]

        if len(neighbors) == 0:
            continue


        neighbor_info = []

        for neighbor in neighbors:

            leaves = 0
            for next_node in adj[neighbor]:
                if next_node != center:
                    leaves += 1
            neighbor_info.append(leaves)


        for y in range(0, max(neighbor_info) + 1):

            valid_intermediates = 0
            for leaves in neighbor_info:
                if leaves >= y:
                    valid_intermediates += 1

            if valid_intermediates > 0:
                x = valid_intermediates
                galaxy_size = 1 + x + x * y
                max_galaxy_size = max(max_galaxy_size, galaxy_size)

    print(n - max_galaxy_size)

main()

