def main():
    M = int(input().strip())
    A = input().strip()
    B = input().strip()

    n, m = len(A), len(B)


    dp = [[float('inf')] * (m + 1) for _ in range(n + 1)]


    for i in range(n + 1):
        dp[i][0] = i
    for j in range(m + 1):
        dp[0][j] = j

    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if A[i-1] == B[j-1]:
                dp[i][j] = dp[i-1][j-1]
            else:
                dp[i][j] = min(
                    dp[i-1][j-1] + 1,
                    dp[i-1][j] + 1,
                    dp[i][j-1] + 1
                )

    if dp[n][m] <= M:
        print("Yes")
    else:
        print("No")

main()

